using TMPro; using UnityEngine; using UnityEngine.UI; using NabyeolDabyeolDreamPuzzle.Collection;
namespace NabyeolDabyeolDreamPuzzle.UI { public class CharacterCardUI:MonoBehaviour{ [SerializeField] TMP_Text nameText,roleText,descriptionText,skillText,statusText; [SerializeField] Image iconImage; [SerializeField] GameObject lockedOverlay,unlockedBadge; CharacterData data; bool unlocked; public void Setup(CharacterData d,bool u){data=d;unlocked=u;Refresh();} public void Refresh(){ if(data==null){Clear(); return;} Set(nameText,unlocked?data.DisplayName:"???"); Set(roleText,unlocked?data.Role:"Locked"); Set(descriptionText,unlocked?data.ShortDescription:"Find more sparkle pieces to unlock."); Set(skillText,unlocked?data.SkillName:"Skill: ???"); Set(statusText,unlocked?"Unlocked":"Locked"); if(iconImage){ if(unlocked&&data.Icon) iconImage.sprite=data.Icon; iconImage.color=unlocked?Color.white:new Color(.25f,.25f,.25f,.65f);} if(lockedOverlay)lockedOverlay.SetActive(!unlocked); if(unlockedBadge)unlockedBadge.SetActive(unlocked);} public void Clear(){ data=null; unlocked=false; Set(nameText,""); Set(roleText,""); Set(descriptionText,""); Set(skillText,""); Set(statusText,""); if(iconImage){iconImage.sprite=null;iconImage.color=Color.white;} if(lockedOverlay)lockedOverlay.SetActive(false); if(unlockedBadge)unlockedBadge.SetActive(false);} void Set(TMP_Text t,string s){ if(t)t.text=s??"";} } }
